1	//! Demo binary: both primitives working across threads,
2	//! with throughput printed — run `cargo run --release`, or
3	//! `cargo install --path . --locked` and run
4	//! `zc-ring-x1-demo`. `-V`/`--version` prints the
5	//! version-of-record so you know exactly which build you
6	//! are testing.
7	//!
8	//! - Part 1, the ring: an SPSC pair moves typed messages
9	//!   in place (reserve_slot → write → commit; reserve_slot
10	//!   → read → release) — first both ends on one thread
11	//!   (the ring's own cost), then one producer thread to
12	//!   one consumer thread: unpinned, pinned to one physical
13	//!   core's two SMT siblings (shared L1/L2), and pinned to
14	//!   two different physical cores.
15	//! - Part 2, the pool: an allocator thread allocs and
16	//!   fills `BufSlot`s and hands them to a freer thread —
17	//!   "send" today is moving the guard (see the README's
18	//!   usage model); getting a buffer implies nothing about
19	//!   when it is sent or freed.
20	//! - The composed form — descriptors through the ring,
21	//!   payloads at rest in pool buffers — is the next cycle;
22	//!   this demo shows each primitive honestly on its own.
23	
24	use std::time::Instant;
25	
26	use zc_ring_x1::{BufSlot, CACHE_LINE_SIZE, Empty, Exhausted, Full, Pool, Ring};
27	use zerocopy::{FromBytes, Immutable, IntoBytes, KnownLayout};
28	
29	/// Messages moved per part.
30	const COUNT: u64 = 1_000_000;
31	
32	/// Ring slots / pool buffers (small on purpose: recycling
33	/// under pressure is the interesting case).
34	const DEPTH: u32 = 64;
35	
36	/// The demo message; one word carrying the sequence number
37	/// the consumer asserts.
38	#[derive(FromBytes, IntoBytes, KnownLayout, Immutable, Debug, PartialEq)]
39	#[repr(C)]
40	struct Msg {
41	    seq: u64,
42	}
43	
44	/// Region for either primitive: biggest header (ring, 4
45	/// lines) + DEPTH one-line slots/buffers.
46	#[repr(C, align(64))]
47	struct Region([u8; 4 * CACHE_LINE_SIZE + DEPTH as usize * CACHE_LINE_SIZE]);
48	
49	/// Group a count into comma-separated thousands
50	/// (`1234567` → `"1,234,567"`).
51	fn commas(n: u64) -> String {
52	    let digits = n.to_string();
53	    let mut out = String::with_capacity(digits.len() + digits.len() / 3);
54	    for (i, c) in digits.chars().enumerate() {
55	        if i > 0 && (digits.len() - i).is_multiple_of(3) {
56	            out.push(',');
57	        }
58	        out.push(c);
59	    }
60	    out
61	}
62	
63	/// Print one part's line: msgs/sec (comma-grouped) and
64	/// ns/msg from the part's elapsed seconds.
65	fn report(label: &str, secs: f64) {
66	    let rate = commas((COUNT as f64 / secs) as u64);
67	    let ns_per_msg = secs * 1e9 / COUNT as f64;
68	    println!("{label:<43} {rate:>12} msgs/sec  {ns_per_msg:>7.1} ns/msg");
69	}
70	
71	/// Parse a /sys cpu-list string ("0,12" or "0-2,6") into cpu
72	/// numbers; malformed pieces are skipped.
73	#[cfg(target_os = "linux")]
74	fn parse_cpu_list(s: &str) -> Vec<usize> {
75	    let mut out = Vec::new();
76	    for part in s.trim().split(',') {
77	        match part.split_once('-') {
78	            Some((lo, hi)) => {
79	                if let (Ok(lo), Ok(hi)) = (lo.parse::<usize>(), hi.parse::<usize>()) {
80	                    out.extend(lo..=hi);
81	                }
82	            }
83	            None => {
84	                if let Ok(n) = part.parse() {
85	                    out.push(n);
86	                }
87	            }
88	        }
89	    }
90	    out
91	}
92	
93	/// A `(producer cpu, consumer cpu)` pin for a 2t run;
94	/// `None` means the pair is unavailable / leave unpinned.
95	type PinPair = Option<(usize, usize)>;
96	
97	/// Discover two cpu pairs for the pinned 2t runs from
98	/// /sys/devices/system/cpu; `None` when the machine lacks the
99	/// shape (or not Linux).
100	///
101	/// - `.0` — same physical core: cpu0 and its SMT sibling
102	///   (shared L1/L2, the cheapest handoff).
103	/// - `.1` — different physical cores: cpu0 and a core outside
104	///   cpu0's L3 group when one exists (the farthest handoff),
105	///   else any non-sibling core.
106	#[cfg(target_os = "linux")]
107	fn discover_pin_pairs() -> (PinPair, PinPair) {
108	    let read = |path: &str| std::fs::read_to_string(path).ok();
109	    let siblings = read("/sys/devices/system/cpu/cpu0/topology/thread_siblings_list")
110	        .map(|s| parse_cpu_list(&s))
111	        .unwrap_or_default();
112	    let smt = (siblings.len() >= 2).then(|| (siblings[0], siblings[1]));
113	    let online = read("/sys/devices/system/cpu/online")
114	        .map(|s| parse_cpu_list(&s))
115	        .unwrap_or_default();
116	    let l3 = read("/sys/devices/system/cpu/cpu0/cache/index3/shared_cpu_list")
117	        .map(|s| parse_cpu_list(&s))
118	        .unwrap_or_else(|| siblings.clone());
119	    let far = online
120	        .iter()
121	        .copied()
122	        .find(|c| !l3.contains(c))
123	        .or_else(|| {
124	            online
125	                .iter()
126	                .copied()
127	                .find(|c| *c != 0 && !siblings.contains(c))
128	        });
129	    (smt, far.map(|c| (0, c)))
130	}
131	
132	/// Non-Linux stub: no pinned runs.
133	#[cfg(not(target_os = "linux"))]
134	fn discover_pin_pairs() -> (PinPair, PinPair) {
135	    (None, None)
136	}
137	
138	/// Pin the calling thread to `cpu` via sched_setaffinity;
139	/// panics on failure (a demo run with a silently ignored pin
140	/// would report a mislabeled number).
141	#[cfg(target_os = "linux")]
142	fn pin_to_cpu(cpu: usize) {
143	    // SAFETY: cpu_set_t is a plain bitmask; CPU_ZERO/CPU_SET
144	    // initialize it fully before sched_setaffinity reads it.
145	    unsafe {
146	        let mut set: libc::cpu_set_t = std::mem::zeroed();
147	        libc::CPU_ZERO(&mut set);
148	        libc::CPU_SET(cpu, &mut set);
149	        let rc = libc::sched_setaffinity(0, size_of::<libc::cpu_set_t>(), &set);
150	        assert_eq!(rc, 0, "sched_setaffinity({cpu}) failed");
151	    }
152	}
153	
154	/// Non-Linux stub: pinning is a no-op, so only the 1t runs
155	/// reach it (discover_pin_pairs returns no pairs); present
156	/// so the demo compiles everywhere.
157	#[cfg(not(target_os = "linux"))]
158	fn pin_to_cpu(_cpu: usize) {}
159	
160	/// Move COUNT messages single thread through the ring,
161	/// pinned to cpu 0 for consistency with the pinned 2t runs;
162	/// return elapsed seconds.
163	///
164	/// The loop runs in a scoped thread rather than pinning the
165	/// main thread: spawned threads inherit the main thread's
166	/// affinity mask, which would squeeze every later part onto
167	/// cpu 0.
168	fn spsc_ring_one_msg_1t() -> f64 {
169	    let mut region = Region([0; size_of::<Region>()]);
170	    let (mut producer, mut consumer) = Ring::init(&mut region.0, CACHE_LINE_SIZE as u32, DEPTH)
171	        .unwrap() // OK: Region is sized/aligned for the ring header + DEPTH slots
172	        .split();
173	
174	    let start = Instant::now();
175	    std::thread::scope(|s| {
176	        s.spawn(move || {
177	            pin_to_cpu(0);
178	            for i in 0..COUNT {
179	                match producer.reserve_slot::<Msg>() {
180	                    Ok(mut slot) => {
181	                        slot.seq = i;
182	                        slot.commit();
183	                    }
184	                    Err(Full) => {
185	                        panic!("spsc_ring_one_msg_1t: producer Full SHOULD NOT HAPPEN");
186	                    }
187	                }
188	                match consumer.reserve_slot::<Msg>() {
189	                    Ok(msg) => {
190	                        assert_eq!(msg.seq, i);
191	                        msg.release();
192	                    }
193	                    Err(Empty) => {
194	                        panic!("spsc_ring_one_msg_1t: consumer Empty SHOULD NOT HAPPEN");
195	                    }
196	                }
197	            }
198	        });
199	    });
200	    start.elapsed().as_secs_f64()
201	}
202	
203	/// Move COUNT messages producer-thread → consumer-thread
204	/// through the ring; return elapsed seconds.
205	///
206	/// - `pin` — `Some((p, c))` pins the producer to cpu `p` and

