280	    ///
281	    /// - Returns the atomic cell, not the value; symmetric
282	    ///   with the header's `first_free_idx`.
283	    /// - Callers pass `idx < buf_count` (validated pops /
284	    ///   init's linking loop), keeping the deref in bounds.
285	    fn next_buf_idx(&self, idx: u32) -> &AtomicU32 {
286	        let p = self.buf_ptr(idx) as *const AtomicU32;
287	        // SAFETY: idx < buf_count keeps the buffer in the
288	        // region validated at init/attach; the base is
289	        // cache-line aligned and buf_size is a line multiple,
290	        // so the first word is 4-aligned; all peers access it
291	        // as an atomic.
292	        unsafe { &*p }
293	    }
294	
295	    /// Pointer to buffer `idx`; callers pass
296	    /// `idx < buf_count`.
297	    fn buf_ptr(&self, idx: u32) -> *mut u8 {
298	        // SAFETY: idx < buf_count, so the offset stays inside
299	        // the buffer array validated at init/attach.
300	        unsafe { self.bufs.add(idx as usize * self.buf_size as usize) }
301	    }
302	}
303	
304	/// An allocated buffer, owned until [`free`](BufSlot::free):
305	/// `DerefMut` to use it as a `T` in place.
306	///
307	/// - Does not borrow the [`Pool`] — hold any number, as long
308	///   as you like; getting a buffer implies nothing about
309	///   when (or whether) it is sent or freed.
310	/// - Dropping without `free` leaks the buffer until the pool
311	///   is re-initialized (the abandon analog of the ring's
312	///   guards, with the opposite consequence).
313	pub struct BufSlot<'p, T> {
314	    /// The pool's control block (for the free CAS).
315	    header: &'p PoolHeader,
316	    /// Base of the owned buffer. Raw, and references are
317	    /// minted per access — same aliasing rationale as the
318	    /// ring guards.
319	    buf: *mut u8,
320	    /// This buffer's index (the value free pushes).
321	    idx: u32,
322	    /// The guard acts as a `&mut T` into the region.
323	    _slot: PhantomData<&'p mut T>,
324	}
325	
326	// SAFETY: the guard owns its buffer exclusively (the pop
327	// removed it from every shared structure); free's CAS is the
328	// only shared-state touch and is properly ordered.
329	unsafe impl<T: Send> Send for BufSlot<'_, T> {}
330	
331	impl<T> Deref for BufSlot<'_, T> {
332	    type Target = T;
333	    /// Read access to the buffer as a `T`.
334	    fn deref(&self) -> &T {
335	        // SAFETY: buf is in-bounds and cache-line aligned
