        // SAFETY: buf is in-bounds and cache-line aligned
        // (validated geometry), any byte pattern is a valid T
        // (FromBytes bound at alloc), and the pop gave this
        // guard sole ownership until free.
        unsafe { &*(self.buf as *const T) }
    }
